import sqlite3

def login(username, password):
    conn = sqlite3.connect('users.db')
    cursor = conn.cursor()

    cursor.execute("""
        SELECT count(*) FROM users WHERE username=? AND password=?
    """, (username, password))

    result = cursor.fetchone()[0]

    if result == 1:
        return True
    else:
        return False

conn.close()